// 사용자 질문 → gemma 분해 요청. mode(search/aggregate) + 구조필터 + semantic_query.
const q = $json.chatInput || $json.chatMessage || "";
const sys = `너는 채용공고 검색 도우미다. status='done'인 공고들이 담긴 jobs 테이블에서 사용자 질문을 처리한다.

[모드]
- search: 특정 직무·기술·역할을 찾는 일반 검색(대부분 여기). 의미검색+구조필터로 처리.
- aggregate: 통계/집계/순위 질문일 때만(예: 기술스택 TOP10, 회사별 공고수, 지역 분포). 이때만 sql에 SELECT 집계문.

[필드]
- mode: "search" 또는 "aggregate"
- semantic_query: search일 때 찾는 직무·기술·역할을 자연어로 정제(예 "온디바이스 AI 모델 경량화·최적화"). aggregate면 "".
- career_lte: 공고 요구경력(min_career)이 이 값 이하인 것만. "N년차/N년 이하/주니어"면 N, "신입"이면 0. 무관이면 -1.
- career_gte: 공고 요구경력이 이 값 이상(시니어). "N년 이상"이면 N. 무관이면 -1.
- location: 지역 키워드(예 "서울","판교"). 무관이면 "".
- tech: 반드시 포함할 핵심 기술 배열(예 ["Python"]). 명시 안 하면 [].
- sql: aggregate일 때만 SELECT 집계문. 기술스택 빈도/순위는 반드시 "SELECT s AS tech, count(*) FROM jobs, unnest(tech_stacks) s WHERE status='done' GROUP BY s ORDER BY count(*) DESC LIMIT N" 형태(배열 통째로 GROUP BY 금지). 회사/지역 집계는 GROUP BY company/locations. SELECT만, 세미콜론·여러문장 금지. search면 "".

- min_score: 이 검색의 관련도 하한(0.40~0.62). 넓고 흔한 직무(백엔드·AI엔지니어·데이터엔지니어)면 0.55~0.60 엄격, 좁고 구체/희귀(온디바이스 경량화·강화학습 로보틱스·벡터DB)면 0.42~0.48 느슨, 보통 0.50. aggregate면 0.50.

[규칙] 애매하면 search. semantic_query엔 지역·경력 조건 넣지 말고 직무·기술 의미만 담아라.`;
const schema = { type:"object", additionalProperties:false, properties:{
  mode:{type:"string", enum:["search","aggregate"]},
  semantic_query:{type:"string"}, career_lte:{type:"integer"}, career_gte:{type:"integer"},
  location:{type:"string"}, tech:{type:"array", items:{type:"string"}}, sql:{type:"string"}, min_score:{type:"number"} },
  required:["mode","semantic_query","career_lte","career_gte","location","tech","sql","min_score"] };
const body = { model: $('설정 (Config)').first().json.sqlModel,
  messages:[{role:"system",content:sys},{role:"user",content:q}],
  temperature:0.1, max_tokens:1500,
  response_format:{type:"json_schema", json_schema:{name:"decomp", schema}} };
return [{ json: { body } }];

// gemma 분해 JSON 파싱 + 방어. 실패 시 search 폴백(질문 전체를 의미검색).
let P; try { P = JSON.parse($json.choices?.[0]?.message?.content || '{}'); } catch(e){ P = {}; }
const chatInput = $('채팅 트리거').first().json.chatInput || '';
const out = {
  mode: P.mode === 'aggregate' ? 'aggregate' : 'search',
  semantic_query: (P.semantic_query && String(P.semantic_query).trim()) ? String(P.semantic_query).trim() : chatInput,
  career_lte: Number.isInteger(P.career_lte) ? P.career_lte : -1,
  career_gte: Number.isInteger(P.career_gte) ? P.career_gte : -1,
  location: typeof P.location === 'string' ? P.location : '',
  tech: Array.isArray(P.tech) ? P.tech : [],
  sql: typeof P.sql === 'string' ? P.sql : '',
  min_score: (typeof P.min_score === 'number') ? P.min_score : null
};
out.emb_input = out.semantic_query || chatInput || ' ';
return [{ json: out }];

// mode에 따라 최종 SQL 생성. aggregate=검증된 raw SELECT, search=하드필터+벡터랭킹.
const P = $('분해 파싱').first().json;
const emb = $json.data && $json.data[0] && $json.data[0].embedding;
const cfgMs = Number($('설정 (Config)').first().json.minScore);
const dyn = $('설정 (Config)').first().json.dynamicThreshold !== false;
const gemMs = Number(P.min_score);
let ms;
if (dyn && Number.isFinite(gemMs) && gemMs > 0) {
  ms = gemMs > 1 ? gemMs/100 : gemMs;
  ms = Math.max(0.40, Math.min(0.65, ms));   // gemma 동적값(안전범위 클램프)
} else {
  ms = Number.isFinite(cfgMs) ? cfgMs : 0.5; // 수동 fallback
  if (ms > 1) ms /= 100;
  if (ms < 0) ms = 0; if (ms > 1) ms = 1;
}
const maxDist = 1 - ms;
const guide = (msg)=>[{json:{sql:`SELECT '${String(msg).replace(/'/g,"''")}' AS 안내`}}];

if (P.mode === 'aggregate' && P.sql && String(P.sql).trim()) {
  let sql = String(P.sql).trim().replace(/;+\s*$/,'');
  if (!/^\s*SELECT\b/i.test(sql)) return guide('집계 쿼리를 이해하지 못했어요.');
  if (/\b(INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|GRANT|REVOKE|TRUNCATE|COPY|MERGE)\b/i.test(sql)) return guide('허용되지 않는 명령이 포함돼 실행하지 않았어요.');
  if (/;/.test(sql)) return guide('한 번에 하나의 쿼리만 실행할 수 있어요.');
  if (/\bLIMIT\s+\d+/i.test(sql)) sql = sql.replace(/\bLIMIT\s+(\d+)/i,(m,n)=>'LIMIT '+Math.min(Number(n),500));
  return [{json:{sql}}];
}
// search 모드: 하드필터(경력·지역·기술) + 벡터 랭킹
if (!Array.isArray(emb) || emb.length !== 1024) return guide('임베딩 서버에 연결하지 못했어요. LM Studio가 켜져 있는지 확인해 주세요.');
const vec = '[' + emb.join(',') + ']';
const esc = s => String(s).replace(/'/g,"''");
const conds = ["status='done'","embedding IS NOT NULL"];
const cl = Number(P.career_lte), cg = Number(P.career_gte);
if (Number.isFinite(cl) && cl>=0) conds.push(`(min_career IS NULL OR min_career <= ${cl})`);
if (Number.isFinite(cg) && cg>=0) conds.push(`min_career >= ${cg}`);
if (P.location && String(P.location).trim()) conds.push(`locations ILIKE '%${esc(String(P.location).trim())}%'`);
for (const t of (Array.isArray(P.tech)?P.tech:[])) { const e = esc(String(t).trim()); if (e) conds.push(`(EXISTS(SELECT 1 FROM unnest(tech_stacks) s WHERE s ILIKE '%${e}%') OR title ILIKE '%${e}%' OR summary ILIKE '%${e}%')`); }
conds.push(`(embedding <=> '${vec}'::vector) <= ${maxDist}`);  // 관련도 하드캡
const where = conds.join(' AND ');
const sql = `SELECT company, title, url, min_career, max_career, tech_stacks, summary, round((1-(embedding <=> '${vec}'::vector))::numeric,3) AS score FROM jobs WHERE ${where} ORDER BY embedding <=> '${vec}'::vector`;
return [{json:{sql}}];

// 결과 포맷 + 마크다운 이스케이프 + Setext 방지 + 파일요청 안내
const rows = $input.all();
const md = (s) => String(s == null ? '' : s).replace(/[\\`*_~#|>\[\]]/g, '\\$&').replace(/\r?\n/g, ' ').trim();
const val = (v) => Array.isArray(v) ? v.map(md).join(', ') : (v === '' || v == null ? '(미분류)' : md(v));
let text;
if (rows.length === 0) { text = '🔎 결과가 없어요.'; }
else {
  const first = rows[0].json; const keys = Object.keys(first);
  if ('sql' in first || 'error' in first) text = '⚠️ 쿼리를 실행하지 못했어요. 질문을 조금 다르게 표현해 주세요.';
  else if (keys.length === 1 && keys[0] === '안내') text = '⚠️ ' + md(first['안내']);
  else if ('title' in first) {
    text = `🔎 **${rows.length}건**\n\n`;
    for (const r of rows) {
      const m = r.json;
      const career = [m.min_career, m.max_career].filter(v => v != null).join('~') || '무관';
      const st = Array.isArray(m.tech_stacks) ? m.tech_stacks.filter(Boolean).map(md).join(', ') : '';
      text += `**${md(m.company)} — ${md(m.title)}**  ·  경력 ${career}${m.score!=null?`  ·  관련도 ${Math.round(m.score*100)}%`:''}\n`;
      if (st) text += `${st}\n`;
      if (m.url) text += `${m.url}\n`;
      text += '\n';
    }
  } else if (keys.length === 1) text = `🔎 결과: **${val(first[keys[0]])}**`;
  else {
    const numKey = keys.find(k => rows.every(r => typeof r.json[k] === 'number' || /^-?\d+(\.\d+)?$/.test(String(r.json[k]))));
    const labelKey = keys.find(k => k !== numKey);
    if (keys.length === 2 && numKey && labelKey) { text = `📊 **${rows.length}개**\n\n`; rows.forEach((r,i)=>{ text += `${i+1}. **${val(r.json[labelKey])}** — ${r.json[numKey]}\n`; }); }
    else { text = `🔎 **${rows.length}행**\n\n| ${keys.map(md).join(' | ')} |\n| ${keys.map(()=>'---').join(' | ')} |\n`; for (const r of rows) text += '| ' + keys.map(k=>val(r.json[k])).join(' | ') + ' |\n'; }
  }
}
// 파일 요청이면 안내 추가
if (!text.startsWith('⚠️') && !text.startsWith('🔎 결과가 없어요')) text += '\n📎 이 결과를 RTF/DOCX 파일로 저장하고 디스코드로 보냈어요.';
return [{ json: { output: text, text } }];

// 질문에 파일/문서/rtf 요청이 있을 때만 RTF 파일 생성. 아니면 [] (파일 안 만듦).
const q = ($('채팅 트리거').first().json.chatInput) || '검색';
const rows = $input.all();
if (rows.length === 0) return [];
const f0 = rows[0].json;
if ('안내' in f0 || 'sql' in f0 || 'error' in f0) return [];  // 검증차단/실패는 파일 안 만듦

// RTF 이스케이프: \ { } 및 비ASCII(한글 등) 유니코드 이스케이프(\uNNNN?)
const esc = (s) => {
  let out = '';
  for (const ch of String(s == null ? '' : s)) {
    const code = ch.codePointAt(0);
    if (ch === '\\') out += '\\\\';
    else if (ch === '{') out += '\\{';
    else if (ch === '}') out += '\\}';
    else if (code > 127) { const c = code > 32767 ? code - 65536 : code; out += '\\u' + c + '?'; }
    else out += ch;
  }
  return out;
};

let bodyRtf = '';
const isJobs = 'title' in rows[0].json;
if (isJobs) {
  bodyRtf += '{\\fs36\\b ' + esc('채용 공고 검색 결과 (' + rows.length + '건)') + '}\\par\\par ';
  for (const r of rows) {
    const m = r.json;
    const career = [m.min_career, m.max_career].filter(v => v != null).join('~') || '무관';
    const st = Array.isArray(m.tech_stacks) ? m.tech_stacks.filter(Boolean).join(', ') : '';
    bodyRtf += '{\\b ' + esc((m.company||'') + ' — ' + (m.title||'')) + '}  (' + esc('경력 ' + career) + ')\\par ';
    if (st) bodyRtf += esc(st) + '\\par ';
    if (m.url) bodyRtf += esc(m.url) + '\\par ';
    bodyRtf += '\\par ';
  }
} else {
  const keys = Object.keys(rows[0].json);
  bodyRtf += '{\\fs36\\b ' + esc('검색 결과 (' + rows.length + '행)') + '}\\par\\par ';
  bodyRtf += '{\\b ' + esc(keys.join(' | ')) + '}\\par ';
  for (const r of rows) bodyRtf += esc(keys.map(k => Array.isArray(r.json[k]) ? r.json[k].join(', ') : r.json[k]).join(' | ')) + '\\par ';
}
const rtf = '{\\rtf1\\ansi\\ansicpg949\\deff0{\\fonttbl{\\f0\\fnil Malgun Gothic;}}\\f0\\fs24 ' + bodyRtf + '}';

// 파일명: 정제 키워드_건수_시각(KST). 원본 질문에서 요청어/조사 제거해 핵심어만 남김.
const FILLER = /(관련된|관련|직무를|직무|직군|포지션|공고를|공고|채용|일자리|자리|찾아주세요|찾아줘|찾아|찾고|찾는|보여주세요|보여줘|알려주세요|알려줘|검색해줘|검색|해주세요|해줘|주세요|싶어요|싶어|싶은|좀|목록|리스트|전체|전부|모두|문서로|문서|파일로|파일|rtf로|rtf|docx로|docx|만들어줘|만들어|줄래|해줄래|주라|줘)/g;
const JOSA = /(으로|로|를|을|은|는|이|가|의|에서|에게|한테|와|과|도|만|랑|이랑|에)$/;
let kw = q.replace(/[\\/:*?"<>|\n\r]+/g, ' ').replace(FILLER, ' ').replace(/\s+/g, ' ').trim();
kw = kw.split(' ').map(t => t.replace(JOSA, '')).filter(Boolean).join('_').replace(/[^\w가-힣_]/g, '').replace(/_+/g, '_').replace(/^_+|_+$/g, '').slice(0, 24);
if (!kw) kw = '검색결과';
const d = new Date();
const pad = (x) => String(x).padStart(2, '0');
const ts = `${pad(d.getMonth()+1)}${pad(d.getDate())}-${pad(d.getHours())}${pad(d.getMinutes())}`;
const filename = `${kw}_${rows.length}건_${ts}.rtf`;
const binary = await this.helpers.prepareBinaryData(Buffer.from(rtf, 'utf-8'), filename, 'application/rtf');
return [{ json: { filename }, binary: { data: binary } }];
